## Code Example
```javascript
// Pseudocode for a slot
class Slot {
  constructor() {
    this.key = 0n; // BigInt for 64-bit
    this.val = 0n;
    this.seq = 0n;
  }
}

function slot_insert(slot, k, v) {
  const cur = atomicLoad(slot.seq);
  if (cur !== 0n) return false;
  if (atomicCompareExchange(slot.seq, cur, 1n)) {
    slot.key = k;
    slot.val = v;
    atomicStore(slot.seq, cur + 1n);
    return true;
  }
  return false;
}

function slot_get(slot, k) {
  const cur = atomicLoad(slot.seq);
  if ((cur & 1n) === 0n) return { found: false };
  if (slot.key === k) return { found: true, val: slot.val };
  return { found: false };
}
```

