## Code Example

```javascript
// Pseudo-code: ring enqueue/dequeue with sequence counters
class Slot { constructor(){ this.seq=0; this.data=null } }
class Ring { constructor(n){ this.size=n; this.mask=n-1; this.buf=Array(n).fill(null).map(()=>new Slot()); this.head=0; this.tail=0 }
  enqueue(x){ const pos = this.head & this.mask; const s = this.buf[pos]; if (s.seq !== this.head) return false; s.data = x; s.seq = this.head + 1; this.head++; return true }
  dequeue(){ const pos = this.tail & this.mask; const s = this.buf[pos]; if (s.seq !== this.tail+1) return null; const v = s.data; s.data=null; s.seq = this.tail + 2; this.tail++; return v }
}}
```

