// Pseudo-code for allocate/free
typedef struct Block { struct Block* next; } Block;
typedef struct Pool { Block* head; void* pool; size_t block_size; } Pool;

Block* allocate(Pool* p){
  Block* old = atomic_load(&p->head);
  while (old){
    Block* next = old->next;
    if (atomic_compare_exchange_weak(&p->head, &old, next)){
      return old;
    }
  }
  return NULL;
}
void deallocate(Pool* p, Block* b){
  Block* head = atomic_load(&p->head);
  do {
    b->next = head;
  } while (!atomic_compare_exchange_weak(&p->head, &head, b));
}
```

