## Code Example
```c
// Minimal sketch
typedef struct { uint64_t seq; char data[256]; } slot_t;
typedef struct { slot_t slots[N]; uint64_t head, tail; } ring_t;

uint64_t pos = __sync_fetch_and_add(&ring->tail, 1);
slot_t *s = &ring->slots[pos % N];
while (s->seq != pos) {}
memcpy(s->data, payload, len);
persist(&s->data, len);
__sync_synchronize();
