// Pseudo implementation sketch
#define BUCKETS 2048
typedef struct Timer {
    void (*cb)(void*);
    void* arg;
    uint32_t expiry;
    struct Timer* next;
} Timer;

static Timer* buckets[BUCKETS];
static pthread_mutex_t locks[BUCKETS];
static volatile uint32_t current_tick = 0;

void add_timer(void (*cb)(void*), void* arg, uint32_t delay_ms) {
    Timer* t = malloc(sizeof(Timer));
    t->cb = cb;
    t->arg = arg;
    t->expiry = current_tick + delay_ms;

    uint32_t bucket_idx = t->expiry % BUCKETS;
    pthread_mutex_lock(&locks[bucket_idx]);
    t->next = buckets[bucket_idx];
    buckets[bucket_idx] = t;
    pthread_mutex_unlock(&locks[bucket_idx]);
}

void tick() {
    uint32_t bucket_idx = current_tick % BUCKETS;
    pthread_mutex_lock(&locks[bucket_idx]);
    Timer* t = buckets[bucket_idx];
    buckets[bucket_idx] = NULL;
    pthread_mutex_unlock(&locks[bucket_idx]);

    while (t) {
        Timer* next = t->next;
        if (t->expiry <= current_tick) {
            t->cb(t->arg);
            free(t);
        }
        t = next;
    }
    current_tick++;
}
```

## Locking Strategy
**Per-bucket locking** reduces contention by allowing concurrent access to different buckets, improving scalability under high timer load. **Global locking** is simpler but becomes a bottleneck with many threads adding timers. Per-bucket spinlocks work well given minimal critical sections and good cache locality.

## Test Plan
1. **Functional correctness**: Schedule timers with varying delays, verify exact callback execution times
2. **Jitter analysis**: Measure actual vs expected execution times to validate ±1ms bounds
3. **Concurrency stress**: Multiple threads adding timers while tick thread processes
4. **Load testing**: Schedule thousands of concurrent timers to validate O(1) performance
5. **Edge cases**: Test with delay = 0, maximum delay, and rapid timer cancellation
6. **Memory validation**: Ensure no timer leaks under high scheduling/cancellation rates

