// Lock-free insert with crash consistency
bool nvml_insert(Node **head, int key, int level) {
  Node *new_node = allocate_nv_node(key, level);
  // Populate and persist node
  clwb(new_node, sizeof(Node));
  sfence();

  for (int l = 0; l < level; l++) {
    Node *pred, *curr;
    do {
      pred = head[l];
      curr = pred->forward[l];
    } while (!validate_link(pred, curr));

    new_node->forward[l] = curr;
    if (!cas(&pred->forward[l], curr, new_node)) {
