- **Memory safety testing**: Validate bounds, check for leaks via allocation/free counts, fuzz with random operations

## Code Example

```c
#include <stdint.h>
#include <stddef.h>
#include <stdbool.h>

#define POOL_SIZE (256 * 1024)    // 256 KiB
#define BLOCK_SIZE 128            // 8-byte aligned
#define NUM_BLOCKS (POOL_SIZE / BLOCK_SIZE)

typedef struct {
    uint32_t next;                // Index of next free block
} free_block_t;

static uint8_t pool[POOL_SIZE];
static uint32_t free_head = 0;    // Head of free list
static bool allocated[NUM_BLOCKS]; // Track block state

void init_pool(void) {
    free_head = 0;
    for (uint32_t i = 0; i < NUM_BLOCKS; i++) {
        free_block_t* block = (free_block_t*)(pool + i * BLOCK_SIZE);
        block->next = (i + 1 < NUM_BLOCKS) ? i + 1 : 0xFFFFFFFF;
        allocated[i] = false;
    }
}

void* allocate(void) {
    if (free_head == 0xFFFFFFFF) return NULL;

    uint32_t index = free_head;
    free_block_t* block = (free_block_t*)(pool + index * BLOCK_SIZE);
    free_head = block->next;
    allocated[index] = true;

    return (void*)block;
}

bool free(void* ptr) {
    if (ptr == NULL || ptr < pool || ptr >= pool + POOL_SIZE) return false;

    uint32_t index = ((uint8_t*)ptr - pool) / BLOCK_SIZE;
    if (index >= NUM_BLOCKS || !allocated[index]) return false; // Double-free protection

    allocated[index] = false;
    free_block_t* block = (free_block_t*)(pool + index * BLOCK_SIZE);
    block->next = free_head;
    free_head = index;

    return true;
}
```

## Testing Strategy

**Fragmentation**: With fixed-size blocks, external fragmentation is impossible. Test by repeatedly allocating and freeing in random patterns; all allocations should succeed until the pool is exhausted.

**Memory Safety**:
