## Code Example
```c
typedef struct Block { uint32_t next; uint8_t payload[64]; } Block;
Block blocks[1024];
atomic_uint head_free;

void init_pool() {
    for (int i = 0; i < 1023; i++) blocks[i].next = i + 1;
    blocks[1023].next = -1;
    head_free = 0;
}

void* allocate_block() {
    uint32_t old_head = head_free;
    do { 
        if (old_head == -1) return NULL;
    } while (!CAS(&head_free, old_head, blocks[old_head].next));
    return blocks[old_head].payload;
}

void free_block(void* ptr) {
    Block* b = container_of(ptr, Block, payload);
    uint32_t old_head;
    do { old_head = head_free; }
    while (!CAS(&head_free, old_head, b - blocks));
    b->next = old_head;
}
```

