} FreeSlot;

#define POOL_SIZE 256
#define SLOT_SIZE 64
static uint8_t pool[POOL_SIZE * SLOT_SIZE];
static uint32_t head = 0; // index of first free slot
static uint32_t used = 0;

void slab_init(void) {
  for (uint32_t i = 0; i < POOL_SIZE - 1; ++i) {
    ((uint32_t*)pool)[i] = i + 1;
  }
  ((uint32_t*)pool)[POOL_SIZE - 1] = UINT32_MAX;
  head = 0;
  used = 0;
}

void* slab_alloc(void) {
  if (head == UINT32_MAX) return NULL;
  uint32_t idx = head;
  head = ((uint32_t*)pool)[idx];
  ++used;
  return pool + idx * SLOT_SIZE;
}

void slab_free(void* p) {
  ptrdiff_t idx = ((uint8_t*)p - pool) / SLOT_SIZE;
  ((uint32_t*)pool)[idx] = head;
  head = (uint32_t)idx;
  --used;
}
