## Code Example
```c
#include <stddef.h>
#include <string.h>

void *memmove64(void *dst, const void *src, size_t n){
  unsigned char *d = (unsigned char*)dst;
  const unsigned char *s = (const unsigned char*)src;
  const size_t BLOCK = 64;

  if ((size_t)(d) <= (size_t)(s) || d >= s + n){
    while (n >= BLOCK){
      memcpy(d, s, BLOCK);
      d += BLOCK; s += BLOCK; n -= BLOCK;
    }
    if (n) memcpy(d, s, n);
  } else {
    d += n; s += n;
    while (n >= BLOCK){
      d -= BLOCK; s -= BLOCK;
      memcpy(d, s, BLOCK);
      n -= BLOCK;
    }
    if (n) memcpy(d - n, s - n, n);
  }
  return dst;
}
```

