#define BLOCK_SIZE 64
#define BLOCK_COUNT 512
static uint8_t pool_mem[BLOCK_SIZE*BLOCK_COUNT];
static uint16_t next_index[BLOCK_COUNT];
static uint16_t free_head;

void pool_init(void) {
  for (uint16_t i = 0; i < BLOCK_COUNT-1; ++i) next_index[i] = i+1;
  next_index[BLOCK_COUNT-1] = 0xFFFF;
  free_head = 0;
}

void* pool_alloc(void) {
  if (free_head == 0xFFFF) return NULL;
  uint16_t idx = free_head;
  free_head = next_index[idx];
  return pool_mem + idx * BLOCK_SIZE;
}

void pool_free(void* ptr) {
  uintptr_t off = (uintptr_t)ptr - (uintptr_t)pool_mem;
  uint16_t idx = off / BLOCK_SIZE;
  next_index[idx] = free_head;
  free_head = idx;
}
