#include <stdatomic.h>
#include <stddef.h>

typedef struct {
  alignas(64) unsigned char arena[4096];
  atomic_uint64_t used;
} Pool;

void* allocate_block(Pool* p) {
  uint64_t oldv = atomic_load_explicit(&p->used, memory_order_relaxed);
  while (1) {
    uint64_t free = ~oldv;
    if (!free) return NULL;
    int idx = __builtin_ctzll(free);
    uint64_t want = oldv | (1ull << idx);
    if (atomic_compare_exchange_weak(&p->used, &oldv, want))
      return (void*)(p->arena + idx * 64);
  }
}

void free_block(Pool* p, void* ptr) {
  size_t idx = ((unsigned char*)ptr - p->arena) / 64;
  uint64_t mask = ~(1ull << idx);
  atomic_fetch_and_explicit(&p->used, mask, memory_order_release);
}
``` 

