  int total;
  _Atomic int sense;
} barrier_t;

void barrier_init(barrier_t *b, int n){ b->count = 0; b->total = n; atomic_store(&b->sense, 0); }

void barrier_wait(barrier_t *b, int *local_sense){
  int my = *local_sense;
  int arrived = atomic_fetch_add_explicit(&b->count, 1, memory_order_acq_rel);
  if (arrived == b->total - 1){
    atomic_store_explicit(&b->count, 0, memory_order_relaxed);
    *local_sense = 1 - my;
    atomic_store_explicit(&b->sense, 1 - atomic_load_explicit(&b->sense, memory_order_relaxed), memory_order_release);
  } else {
    while (atomic_load_explicit(&b->sense, memory_order_acquire) == my) { /* spin */ }
  }
}
```

