typedef struct Block { struct Block *next; char pad[56]; } Block;

typedef struct { _Atomic(Block *) head; } FreeList;

static inline void* pool_alloc(FreeList *g, _Atomic(Block *) *local, int *lcnt) {
    if (*lcnt == 0) {
        Block *batch[32];
        Block *head = atomic_load_explicit(&g->head, memory_order_acquire);
        do { for (int i = 0; i < 31; i++) batch[i] = batch[i]->next; } 
        while (!atomic_compare_exchange_weak(&g->head, &head, batch[31]));
        *lcnt = 31;
        return batch[0];
    }
    return local[--*lcnt];
}

static inline void pool_free(FreeList *g, _Atomic(Block *) *local, int *lcnt, void *ptr) {
    if (*lcnt == 32) {
        Block *head = atomic_load_explicit(&g->head, memory_order_relaxed);
        do { local[31] = head; } while (!atomic_compare_exchange_weak(&g->head, &head, local[0]));
        *lcnt = 0;
    }
    local[(*lcnt)++] = ptr;
}
```

