  uint64_t value;
  uint32_t seq;        // sequence counter
  uint8_t  state;      // 0=empty, 1=filled, 2=tombstone
} bucket_t;

bucket_t* table = aligned_alloc(64, N * sizeof(bucket_t));

// PUT: lock-free insert with CAS
bool put(uint64_t key, uint64_t value) {
  uint32_t h = hash(key) & (N-1);
  for (int i = 0; i < MAX_PROBE; ++i) {
    bucket_t* b = &table[(h + i) & (N-1)];
    uint32_t seq = b->seq;
    if (b->state == 0) {  // empty
      bucket_t new = {key, value, seq, 1};
      if (__sync_bool_compare_and_swap(b, &new, sizeof(bucket_t))) {
        return true;
      }
    }
  }
  return false;
}

// GET: validate sequence to avoid ABA
uint64_t get(uint64_t key) {
  uint32_t h = hash(key) & (N-1);
  for (int i = 0; i < MAX_PROBE; ++i) {
    bucket_t* b = &table[(h + i) & (N-1)];
    if (b->state == 0) return NOT_FOUND;
    if (b->state == 1 && b->key == key) {
      // re-check sequence for ABA safety
      if (b->seq == expected_seq) return b->value;
    }
  }
  return NOT_FOUND;
}
```

