## Code Example
```c
#include <immintrin.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define CHUNK_SIZE 64
#define TAIL_SIZE 31

typedef struct {
    size_t* positions;
    size_t count;
    size_t capacity;
} MatchResults;

static inline __m512i broadcast_pattern(const unsigned char* pat, size_t pat_len) {
    __m512i v = _mm512_setzero_si512();
    for (size_t i = 0; i < pat_len && i < 64; i++) {
        v = _mm512_set1_epi8(pat[i]);
    }
    return v;
}

void search_simd(const unsigned char* data, size_t n,
                 const unsigned char* pat, size_t pat_len,
                 MatchResults* results) {
    const size_t vec_width = 64;
    unsigned char tail[TAIL_SIZE] = {0};
    size_t tail_len = 0;

    size_t i = 0;
    for (; i + vec_width <= n; i += vec_width) {
        __m512i v = _mm512_loadu_si512((__m512i*)(data + i));
        __m512i p = _mm512_set1_epi8(pat[0]);
        __m512i cmp = _mm512_cmpeq_epi8(v, p);
        uint64_t mask = _mm512_mask_reduce_u64(cmp);

        while (mask) {
            uint64_t bit = __builtin_ctzll(mask);
            size_t pos = i + bit;
            if (pos + pat_len <= n && 
                memcmp(data + pos, pat, pat_len) == 0) {
                if (results->count < results->capacity) {
                    results->positions[results->count++] = pos;
                }
            }
            mask &= mask - 1;
        }
    }

    tail_len = n - i;
    if (tail_len > 0) {
        memcpy(tail, data + i, tail_len);
    }
    for (size_t j = 0; j < pat_len && tail_len + j < CHUNK_SIZE; j++) {
        tail[tail_len + j] = pat[j];
    }

    for (size_t j = 0; j < tail_len; j++) {
        if (j + pat_len <= tail_len + pat_len &&
            memcmp(tail + j, pat, pat_len) == 0) {
            if (results->count < results->capacity) {
                results->positions[results->count++] = i + j;
            }
        }
    }
}

double benchmark_search(const unsigned char* data, size_t n,
                       const unsigned char* pat, size_t pat_len,
                       int use_simd, size_t iterations) {
    struct timespec start, end;
    MatchResults results = {
        .positions = malloc(n * sizeof(size_t)),
        .count = 0,
        .capacity = n
    };

    clock_gettime(CLOCK_MONOTONIC, &start);
    for (size_t iter = 0; iter < iterations; iter++) {
        results.count = 0;
        if (use_simd) {
            search_simd(data, n, pat, pat_len, &results);
        } else {
            for (size_t i = 0; i + pat_len <= n; i++) {
                if (memcmp(data + i, pat, pat_len) == 0) {
                    if (results.count < results.capacity) {
                        results.positions[results.count++] = i;
                    }
                }
            }
        }
    }
    clock_gettime(CLOCK_MONOTONIC, &end);

    free(results.positions);
    return (end.tv_sec - start.tv_sec) + 
           (end.tv_nsec - start.tv_nsec) / 1e9;
}
```

## Microbenchmark Plan
1. **Baseline**: Scalar `memcmp`/byte-by-byte search across full dataset
2. **Test Cases**:
