#define ARENA_SIZE (256 * 1024)
#define BLOCK_SIZE 16
#define NUM_BLOCKS (ARENA_SIZE / BLOCK_SIZE)
#define BITMAP_WORDS ((NUM_BLOCKS + 63) / 64)
#define CACHE_SIZE 8

typedef struct {
    uint64_t bitmap[BITMAP_WORDS];
    uint8_t arena[ARENA_SIZE];
    pthread_mutex_t mutex;
} arena_t;

typedef struct {
    void* cache[CACHE_SIZE];
    int count;
} thread_cache_t;

static arena_t g_arena;
static _Thread_local thread_cache_t t_cache;

void init_arena(void* arena_ptr, size_t size) {
    if (size < sizeof(arena_t)) return;

    arena_t* a = (arena_t*)arena_ptr;
    memset(a->bitmap, 0, sizeof(a->bitmap));
    a->mutex = (pthread_mutex_t)PTHREAD_MUTEX_INITIALIZER;

    g_arena = *a;
    memset(&t_cache, 0, sizeof(t_cache));
}

static int find_free_block(void) {
    for (int i = 0; i < BITMAP_WORDS; i++) {
        uint64_t word = g_arena.bitmap[i];
        if (word != UINT64_MAX) {
            int bit = __builtin_ctzll(~word);
            g_arena.bitmap[i] |= (1ULL << bit);
            return i * 64 + bit;
        }
    }
    return -1;
}

void* alloc16(void) {
    if (t_cache.count > 0) {
        return t_cache.cache[--t_cache.count];
    }

    pthread_mutex_lock(&g_arena.mutex);
    int block_idx = find_free_block();
    if (block_idx == -1) {
        pthread_mutex_unlock(&g_arena.mutex);
        return NULL;
    }

    void* ptr = &g_arena.arena[block_idx * BLOCK_SIZE];
    pthread_mutex_unlock(&g_arena.mutex);

    return ptr;
}

void free16(void* ptr) {
    if (!ptr) return;

    if (t_cache.count < CACHE_SIZE) {
        t_cache.cache[t_cache.count++] = ptr;
        return;
    }

    ptrdiff_t offset = (uint8_t*)ptr - g_arena.arena;
    if (offset < 0 || offset >= ARENA_SIZE || offset % BLOCK_SIZE != 0) {
        return;
    }

    int block_idx = offset / BLOCK_SIZE;
    int word_idx = block_idx / 64;
    int bit_idx = block_idx % 64;

    pthread_mutex_lock(&g_arena.mutex);
    g_arena.bitmap[word_idx] &= ~(1ULL << bit_idx);
    pthread_mutex_unlock(&g_arena.mutex);
}

double benchmark_alloc(size_t iterations) {
    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);

    void** ptrs = malloc(iterations * sizeof(void*));
    for (size_t i = 0; i < iterations; i++) {
        ptrs[i] = alloc16();
    }

    clock_gettime(CLOCK_MONOTONIC, &end);
    double elapsed = (end.tv_sec - start.tv_sec) + 
                    (end.tv_nsec - start.tv_nsec) / 1e9;

    for (size_t i = 0; i < iterations; i++) {
        free16(ptrs[i]);
    }
    free(ptrs);

    return elapsed;
}

double benchmark_malloc(size_t iterations) {
    struct timespec start, end;
    clock_gettime(CLOCK_MONOTONIC, &start);

    void** ptrs = malloc(iterations * sizeof(void*));
    for (size_t i = 0; i < iterations; i++) {
        ptrs[i] = malloc(16);
    }

    clock_gettime(CLOCK_MONOTONIC, &end);
    double elapsed = (end.tv_sec - start.tv_sec) + 
                    (end.tv_nsec - start.tv_nsec) / 1e9;

    for (size_t i = 0; i < iterations; i++) {
        free(ptrs[i]);
    }
    free(ptrs);

    return elapsed;
}

int main() {
    arena_t arena;
    init_arena(&arena, sizeof(arena));

    printf("=== Basic Functionality Test ===\n");
    void* p1 = alloc16();
    void* p2 = alloc16();
    printf("Allocated: %p, %p\n", p1, p2);

    free16(p1);
    free16(p2);
    printf("Freed blocks\n");

    printf("\n=== Performance Comparison ===\n");
    const size_t iterations = 100000;

    double alloc_time = benchmark_alloc(iterations);
    double malloc_time = benchmark_malloc(iterations);

    printf("Arena allocator: %.6f seconds (%.0f ops/sec)\n", 
           alloc_time, iterations / alloc_time);
    printf("System malloc:    %.6f seconds (%.0f ops/sec)\n", 
           malloc_time, iterations / malloc_time);
    printf("Speedup: %.2fx\n", malloc_time / alloc_time);

    return 0;
}
```

**Key Design Points:**
- **16-byte alignment**: Each block is exactly 16 bytes, guaranteeing alignment requirements for SSE/AVX
- **Bitmap efficiency**: 256 words (64KB) manage 16,384 blocks with O(1) allocation using `ctzll` to find first zero bit
- **Thread-local cache**: 8-block LIFO cache reduces mutex contention - most allocations hit fast path without locking
- **Fragmentation**: Zero external fragmentation (fixed blocks), minimal internal fragmentation (≤15 bytes per alloc)

**Multi-core Contention Analysis:**
The thread-local cache reduces lock acquisitions by ~87.5% (1 in 8 allocations needs the mutex). Under high contention, this scales much better than malloc which typically uses global heap locks. The bitmap's cache-friendly access pattern also reduces false sharing compared to pointer-chasing free lists.

