void tlb_insert(uint32_t va, uint32_t pa){ uint32_t page = va >> 12; uint32_t idx = page & 0xFF; int miss_pos = -1; uint8_t oldest = 0; for(int i=0;i<256;i++){ tlb_entry* e = &tlb[(idx+i)&0xFF]; if(!e->valid){ miss_pos = (idx+i)&0xFF; break; } if(e->lru > oldest){ oldest = e->lru; miss_pos = (idx+i)&0xFF; } }
 tlb[miss_pos].tag = page; tlb[miss_pos].pa = pa; tlb[miss_pos].valid = 1; tlb[miss_pos].lru = 0; }
