static uint32_t crc32_table[256];

void init_crc32_table(void){
  const uint32_t poly = 0xEDB88320U;
  for (int i=0;i<256;i++){
    uint32_t c = i;
    for (int j=0;j<8;j++) c = (c & 1) ? (c >> 1) ^ poly : (c >> 1);
    crc32_table[i] = c;
