uint32_t crc32_update(uint32_t crc, const uint8_t* data, size_t len){
  crc ^= 0xFFFFFFFFU;
  for (size_t i=0;i<len;i++){
    crc = crc32_table[(crc ^ data[i]) & 0xFF] ^ (crc >> 8);
  }
  return crc ^ 0xFFFFFFFFU;
}

