  size_t idx = probe(k);
  for (size_t i = 0; i < N; ++i) {
    if (keys[idx] == 0) { keys[idx] = k; vals[idx] = v; return 0; }
    if (keys[idx] == k) { vals[idx] = v; return 0; }
    idx = (idx + 1) % N;
