    unsigned pos = q->tail;
    if ((pos + 1) % q->cap == q->head) return -1; // full

    unsigned status = _xbegin();
    if (status == _XBEGIN_STARTED) {
        q->slots[pos].val = val;
        q->slots[pos].seq = pos + 1;
        q->tail = (pos + 1) % q->cap;
