questions.answer:
Cross-NUMA, two-process ring for 40 Gbps on a dual-socket server. Slot: 128 bytes; capacity 1<<18; 64-byte alignment; per-slot 64-bit sequence for ABA-avoidance. NUMA-aware allocation on local node.

## Slot Layout
```c
struct slot {
    uint64_t seq;           // 8 bytes - sequence number
    uint64_t reserved;      // 8 bytes - padding
    char data[112];         // 112 bytes - payload (128-16)
} __attribute__((aligned(64)));  // Cache-line aligned

struct ring_buffer {
    uint64_t head;          // Consumer position
    uint64_t tail;          // Producer position  
    char pad[64 - 16];      // Cache-line padding
    struct slot slots[1<<18]; // 256KB total
} __attribute__((aligned(64)));
```

## Enqueue (Producer on Socket A)
```c
bool enqueue(struct ring_buffer* rb, const void* data, size_t len) {
    uint64_t pos, idx, seq;

    // Get current tail position
    pos = __atomic_load_n(&rb->tail, __ATOMIC_RELAXED);

    // Check if ring is full (head + capacity)
    uint64_t head = __atomic_load_n(&rb->head, __ATOMIC_ACQUIRE);
    if (pos - head >= (1<<18)) return false; // Backpressure

    idx = pos & ((1<<18) - 1);
    struct slot* slot = &rb->slots[idx];

    // Load current sequence to check slot availability
    seq = __atomic_load_n(&slot->seq, __ATOMIC_ACQUIRE);
    if (seq != pos) return false; // Slot not ready

    // Copy payload (non-temporal for cross-NUMA)
    __builtin_memcpy(&slot->data, data, len);

    // Memory fence before publishing
    __atomic_thread_fence(__ATOMIC_RELEASE);

    // Publish new sequence (ABA-safe)
    __atomic_store_n(&slot->seq, pos + 1, __ATOMIC_RELEASE);

    // Advance tail position
    __atomic_store_n(&rb->tail, pos + 1, __ATOMIC_RELAXED);
    return true;
}
```

## Dequeue (Consumer on Socket B)
```c
bool dequeue(struct ring_buffer* rb, void* data, size_t* len) {
    uint64_t pos, idx, seq;

    // Get current head position
    pos = __atomic_load_n(&rb->head, __ATOMIC_RELAXED);

    idx = pos & ((1<<18) - 1);
    struct slot* slot = &rb->slots[idx];

    // Check if slot is ready
    seq = __atomic_load_n(&slot->seq, __ATOMIC_ACQUIRE);
    if (seq != pos + 1) return false; // No data available

    // Copy payload
    *len = 112; // Fixed payload size
    __builtin_memcpy(data, &slot->data, *len);

    // Memory fence before reclaiming
    __atomic_thread_fence(__ATOMIC_RELEASE);

    // Mark slot as free (wrap-around safe)
    __atomic_store_n(&slot->seq, pos + 2, __ATOMIC_RELEASE);

    // Advance head position
    __atomic_store_n(&rb->head, pos + 1, __ATOMIC_RELAXED);
    return true;
}
```

## NUMA Allocation
```c
// Allocate on socket A (producer side)
void* alloc_numa_socketA(size_t size) {
    void* ptr = numa_alloc_onnode(size, 0); // Socket 0
    mlock(ptr, size); // Pin in memory
    return ptr;
}
```

## Microbenchmark
```c
void benchmark_cross_numa() {
    const size_t iterations = 10000000;
    const size_t payload_size = 112;

    // Setup: fork processes, bind to sockets
    pid_t consumer = fork();
    if (consumer == 0) {
        // Consumer process - bind to socket B
        cpu_set_t mask;
        CPU_ZERO(&mask);
        for (int i = 8; i < 16; i++) CPU_SET(i, &mask);
        sched_setaffinity(0, sizeof(mask), &mask);

        // Run consumer loop, measure throughput
        auto start = std::chrono::high_resolution_clock::now();
        size_t received = 0;
        while (received < iterations) {
            if (dequeue(rb, buffer, &len)) {
                // Verify data integrity
                if (verify_checksum(buffer, len)) received++;
            }
        }
        auto end = std::chrono::high_resolution_clock::now();

        double throughput = (received * payload_size * 8) / 
            std::chrono::duration<double>(end - start).count() / 1e9;
        printf("Throughput: %.2f Gbps\n", throughput);
    }

    // Producer process - bind to socket A
    cpu_set_t mask;
    CPU_ZERO(&mask);
    for (int i = 0; i < 8; i++) CPU_SET(i, &mask);
    sched_setaffinity(0, sizeof(mask), &mask);

    // Generate test data with checksums
    for (size_t i = 0; i < iterations; ) {
        if (enqueue(rb, test_data + (i % 1000), payload_size)) {
            i++;
        } else {
            _mm_pause(); // Backpressure handling
        }
    }
}
```

