typedef struct { _Atomic uint64_t slot; } Mailbox;
void mailbox_init(Mailbox *m){ atomic_init(&m->slot, 0); }
bool mailbox_send(Mailbox *m, uint32_t payload){
  uint64_t cur = atomic_load_explicit(&m->slot, memory_order_relaxed);
  uint32_t seq = (uint32_t)(cur>>32);
  uint64_t want = ((uint64_t)seq<<32);
  uint64_t next = (((uint64_t)(seq+1))<<32) | payload;
  return atomic_compare_exchange_strong(&m->slot, &want, next);
}
bool mailbox_recv(Mailbox *m, uint32_t *out){
  uint64_t cur = atomic_load_explicit(&m->slot, memory_order_acquire);
  uint32_t seq = (uint32_t)(cur>>32);
  uint32_t payload = (uint32_t)(cur & 0xFFFFFFFF);
  if (payload == 0) return false;
  uint64_t next = (((uint64_t)(seq+1))<<32) | 0u;
  if (atomic_compare_exchange_strong(&m->slot, &cur, next)){
    *out = payload; return true;
  }
  return false;
}
```

