Implement a crash-consistent ring buffer with head/tail stored in DRAM for performance and per-slot metadata in NVRAM for durability. Use a two-phase commit protocol: (1) write payload to NVRAM slot, (2) flush with clwb, (3) sfence for ordering, (4) atomically set valid flag, (5) advance head pointer. Consumers validate entries by checking valid flags, read data, clear flags, and advance tail. Periodically checkpoint head/tail to NVRAM (every N operations) to bound recovery time. Recovery scans from last checkpoint to find first valid slot after the tail position, reconstructing the ring state.

API prototypes:
```c
int nvring_init(nvring_t* ring, void* nvram_base, size_t capacity);
int nvring_produce(nvring_t* ring, const void* data, size_t len);
int nvring_consume(nvring_t* ring, void* data, size_t* len);
int nvring_recover(nvring_t* ring);
```

Pseudo-code:
```c
int nvring_produce(nvring_t* ring, const void* data, size_t len) {
    uint64_t head = atomic_load(&ring->head);
    uint64_t slot_idx = head % ring->capacity;
    nvslot_t* slot = &ring->slots[slot_idx];

    // Phase 1: Write data
    memcpy(&slot->data, data, len);
    slot->len = len;

    // Phase 2: Make durable
    clwb(&slot->data);
    clwb(&slot->len);
    sfence();

    // Phase 3: Commit
    atomic_store(&slot->valid, 1);
    atomic_store(&ring->head, head + 1);

    return 0;
}

int nvring_recover(nvring_t* ring) {
    uint64_t checkpoint = ring->checkpoint_head;
    uint64_t tail = ring->checkpoint_tail;

    for (uint64_t i = tail; i < checkpoint + ring->capacity; i++) {
        uint64_t slot_idx = i % ring->capacity;
        nvslot_t* slot = &ring->slots[slot_idx];

        if (atomic_load(&slot->valid)) {
            atomic_store(&ring->head, i + 1);
        } else {
            atomic_store(&ring->tail, i);
            break;
        }
    }
    return 0;
}
```

