## Code Example

```c
typedef struct Block {
  struct Block* next;
} Block;

typedef struct Arena {
  Block* blocks;
  size_t count;
} Arena;

static __thread Block* freelist_head = NULL;

void init_arena(Arena* a, void* mem, size_t blocks) {
  a->blocks = (Block*)mem;
  a->count = blocks;
  for (size_t i = 0; i + 1 < blocks; ++i) {
    a->blocks[i].next = &a->blocks[i+1];
  }
  a->blocks[blocks - 1].next = NULL;
  freelist_head = a->blocks;
}

void* tl_alloc() {
  Block* b = freelist_head;
  if (!b) return NULL;
  freelist_head = b->next;
  return (void*)b;
}

void tl_free(void* p) {
  ((Block*)p)->next = freelist_head;
  freelist_head = (Block*)p;
}
```

