#include <immintrin.h>

typedef struct { alignas(64) atomic_flag flag; } spinlock_t;

void spinlock_init(spinlock_t *s){ atomic_flag_clear(&s->flag); }
void spin_lock(spinlock_t *s){
  int backoff = 1;
  while (atomic_flag_test_and_set_explicit(&s->flag, memory_order_acquire)) {
    for (volatile int i = 0; i < backoff; ++i) _mm_pause();
    if (backoff < 64) backoff <<= 1;
  }
}
void spin_unlock(spinlock_t *s){ atomic_flag_clear_explicit(&s->flag, memory_order_release); }
```

